+        // Find matching closing bracket to ignore trailing noise.
+        let json_end = json_slice
+            .find("]\n")
+            .or_else(|| json_slice.rfind(']'))
+            .map_or(json_slice.len(), |i| i + 1);
         let parsed: serde_json::Value =
